def gen(rng, size):
    def build(depth):
        if depth <= 0 or rng.random() < 0.45:
            return rng.randint(-1000000, 1000000)
        n = rng.randint(0, 5)
        return [build(depth - 1) for _ in range(n)]
    count = max(1, size // 30)
    top = [build(3) for _ in range(count)]
    def fmt(x):
        if isinstance(x, list):
            return '[' + ','.join(fmt(e) for e in x) + ']'
        return str(x)
    return [fmt(top)]

