def _oracle_deserialize(s):
    if s[0] != '[':
        return int(s)
    stack = []
    num = ''
    result = None
    for ch in s:
        if ch == '[':
            stack.append([])
        elif ch == ']':
            if num:
                stack[-1].append(int(num))
                num = ''
            popped = stack.pop()
            if stack:
                stack[-1].append(popped)
            else:
                result = popped
        elif ch == ',':
            if num:
                stack[-1].append(int(num))
                num = ''
        else:
            num += ch
    return result


class Solution:
    def deserialize(self, s):
        return _oracle_deserialize(s)

