class Solution:
    def deserialize(self, s):
        def parse(i):
            if s[i] == '[':
                i += 1
                lst = []
                if s[i] == ']':
                    return lst, i + 1
                while True:
                    val, i = parse(i)
                    lst.append(val)
                    if s[i] == ',':
                        i += 1
                    elif s[i] == ']':
                        i += 1
                        break
                return lst, i
            else:
                j = i
                while j < len(s) and s[j] not in ',]':
                    j += 1
                return int(s[i:j]), j
        value, _ = parse(0)
        return value

