var deserialize = function(s) {
    function parse(i) {
        if (s[i] === '[') {
            i += 1;
            const lst = [];
            if (s[i] === ']') {
                return [lst, i + 1];
            }
            while (true) {
                const r = parse(i);
                lst.push(r[0]);
                i = r[1];
                if (s[i] === ',') {
                    i += 1;
                } else if (s[i] === ']') {
                    i += 1;
                    break;
                }
            }
            return [lst, i];
        } else {
            let j = i;
            while (j < s.length && s[j] !== ',' && s[j] !== ']') {
                j += 1;
            }
            return [parseInt(s.slice(i, j), 10), j];
        }
    }
    return parse(0)[0];
};
